# # # # # # # # # # # # # # # # # # # # # # # #     R = 6371.0
# # # # # # # # # # # # # # # # # # # # # # # #     lon1, lat1 = np.radians(pred_deg[:, 0]), np.radians(pred_deg[:, 1])
# # # # # # # # # # # # # # # # # # # # # # # #     lon2, lat2 = np.radians(gt_deg[:, 0]),   np.radians(gt_deg[:, 1])
