# # # # # # # # # # # # # # # # # # # # # # # # def evaluate_fast(model, loader, device, ode_steps, pred_len, fast_ensemble=8):
# # # # # # # # # # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # # # # # # # # # #     FIX-T24-7: Log th├¬m per-step spread ─Ĺß╗â monitor FIX-L46.
# # # # # # # # # # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # # # # # # # # # #     import torch
