# # # # # # # # # # # # # # # # # # # # # # #                Chß╗ë train ShortRangeHead + ctx_fc/transformer. LR=5e-4.
# # # # # # # # # # # # # # # # # # # # # # #                Mß╗ąc ti├¬u: ShortRangeHead hß╗Źc motion pattern nhanh.
# # # # # # # # # # # # # # # # # # # # # # #              Phase 2 (ep 30+): Unfreeze to├án bß╗Ö. LR=2e-4.
# # # # # # # # # # # # # # # # # # # # # # #                Mß╗ąc ti├¬u: Fine-tune end-to-end vß╗Ťi ─Ĺß║žy ─Ĺß╗ž loss.

# # # # # # # # # # # # # # # # # # # # # # #   FIX-T24-B  [PRIMARY METRIC: 12h ADE]
# # # # # # # # # # # # # # # # # # # # # # #              BestModelSaver giß╗Ł track best_12h_ade thay v├Č overall ADE.
# # # # # # # # # # # # # # # # # # # # # # #              Early stopping dß╗▒a tr├¬n 12h ADE (tol=3 km).
# # # # # # # # # # # # # # # # # # # # # # #              Overall ADE vß║źn log nhĂ░ng kh├┤ng quyß║┐t ─Ĺß╗őnh best model.

# # # # # # # # # # # # # # # # # # # # # # #   FIX-T24-C  [SHORT-RANGE LOSS WEIGHT SCHEDULE]
# # # # # # # # # # # # # # # # # # # # # # #              Ep 0-30 : short_range weight = 8.0 (focus mß║ính v├áo 12h/24h)
# # # # # # # # # # # # # # # # # # # # # # #              Ep 30-60: short_range weight = 5.0 (c├ón bß║▒ng)
# # # # # # # # # # # # # # # # # # # # # # #              Ep 60+  : short_range weight = 3.0 (duy tr├Č)

# # # # # # # # # # # # # # # # # # # # # # #   FIX-T24-D  [SPREAD CONTROL ─Éß║ŽU TRAINING]
# # # # # # # # # # # # # # # # # # # # # # #              initial_sample_sigma=0.03, ctx_noise_scale=0.002
# # # # # # # # # # # # # # # # # # # # # # #              T─âng spread_weight l├¬n 1.2 trong 30 epoch ─Ĺß║žu ─Ĺß╗â ├ęp
# # # # # # # # # # # # # # # # # # # # # # #              ensemble kh├┤ng b├╣ng nß╗Ľ ngay tß╗ź ─Ĺß║žu.

# # # # # # # # # # # # # # # # # # # # # # #   FIX-T24-E  [PINN WARMUP D├ÇI HĂáN]
