# # # # # # # # # # # # # # # # # # # # # # #             out[i] = x.to(device)
# # # # # # # # # # # # # # # # # # # # # # #         elif isinstance(x, dict):
# # # # # # # # # # # # # # # # # # # # # # #             out[i] = {k: v.to(device) if torch.is_tensor(v) else v
# # # # # # # # # # # # # # # # # # # # # # #                       for k, v in x.items()}
# # # # # # # # # # # # # # # # # # # # # # #     return out


