# # # # # # # # # # # # # # # # # # # # # # # def get_pinn_weight(epoch, warmup_epochs=80,
# # # # # # # # # # # # # # # # # # # # # # #                     w_start=0.001, w_end=0.05):
# # # # # # # # # # # # # # # # # # # # # # #     # FIX: t─âng nhanh hĂín trong phase 2 (sau ep 30)
# # # # # # # # # # # # # # # # # # # # # # #     if epoch < 30:
# # # # # # # # # # # # # # # # # # # # # # #         # Phase 1: PINN rß║ąt nhß╗Ć, focus ShortRangeHead
# # # # # # # # # # # # # # # # # # # # # # #         return w_start
# # # # # # # # # # # # # # # # # # # # # # #     elif epoch < warmup_epochs:
# # # # # # # # # # # # # # # # # # # # # # #         # Phase 2: t─âng tuyß║┐n t├şnh tß╗ź 0.005 Ôćĺ w_end
