# # # # # # # # # # # # # # # # # # # # # def get_pinn_weight(epoch: int, warmup_epochs: int = 60,
# # # # # # # # # # # # # # # # # # # # #                     w_start: float = 0.001, w_end: float = 0.03) -> float:
# # # # # # # # # # # # # # # # # # # # #     """PINN: gentle warmup, lower max (0.03 instead of 0.05)"""
