# # # # # # # # # # # # # # # # # # # # ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ

# # # # # # # # # # # # # # # # # # # # KEY CHANGES tß╗ź v30 train script:
# # # # # # # # # # # # # # # # # # # #   1. Bß╗Ä tß║ąt cß║ú weight schedules phß╗ęc tß║íp Ôćĺ chß╗ë cß║žn MSE
# # # # # # # # # # # # # # # # # # # #   2. Bß╗Ä SR-specific evaluation Ôćĺ FM predict all steps
# # # # # # # # # # # # # # # # # # # #   3. Bß╗Ä AFCRPS, PINN, continuity, spread schedules
# # # # # # # # # # # # # # # # # # # #   4. TH├ŐM sigma_min schedule logging
# # # # # # # # # # # # # # # # # # # #   5. Learning rate: cosine vß╗Ťi warmup, peak = 3e-4 (cao hĂín v32)
# # # # # # # # # # # # # # # # # # # #   6. Grad clip: 1.0 constant (kh├┤ng cß║žn schedule)
# # # # # # # # # # # # # # # # # # # #   7. Grad accum = 1 (─ĹĂín giß║ún h├│a)
# # # # # # # # # # # # # # # # # # # # """
