# # # # # # # # # # # # # # # # # #         h72  = r.get("72h", float("inf"))
# # # # # # # # # # # # # # # # # #         score = _composite_score(r)

# # # # # # # # # # # # # # # # # #         improved_score = score < self.best_score - self.tol
# # # # # # # # # # # # # # # # # #         improved_any   = False

# # # # # # # # # # # # # # # # # #         sd = self._unwrap_state_dict(model)

# # # # # # # # # # # # # # # # # #         if ade < self.best_ade:
