# # # # # # # # # # # # # # # # #  Composite Score v2 ÔÇö normalize theo ST-Trans targets
# # # # # # # # # # # # # # # # # ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ

# # # # # # # # # # # # # # # # def _composite_score(result: dict) -> float:
# # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # #     Lower = better. score < 100 Ôćĺ beat ST-Trans tr├¬n tß║ąt cß║ú metrics.

# # # # # # # # # # # # # # # #     ST-Trans targets: DPE=136.41, ATE=79.94, CTE=93.58, 72hÔëł297
# # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # #     ade = result.get("ADE", float("inf"))
# # # # # # # # # # # # # # # #     h12 = result.get("12h", float("inf"))
# # # # # # # # # # # # # # # #     h24 = result.get("24h", float("inf"))
# # # # # # # # # # # # # # # #     h48 = result.get("48h", float("inf"))
# # # # # # # # # # # # # # # #     h72 = result.get("72h", float("inf"))
# # # # # # # # # # # # # # # #     ate = result.get("ATE_mean", float("inf"))
# # # # # # # # # # # # # # # #     cte = result.get("CTE_mean", float("inf"))

# # # # # # # # # # # # # # # #     # Fallback nß║┐u chĂ░a c├│ ATE/CTE
# # # # # # # # # # # # # # # #     if not np.isfinite(ate): ate = ade * 0.46
# # # # # # # # # # # # # # # #     if not np.isfinite(cte): cte = ade * 0.53

# # # # # # # # # # # # # # # #     score = (
# # # # # # # # # # # # # # # #         0.05 * (ade / 136.0)
# # # # # # # # # # # # # # # #         + 0.05 * (h12 / 50.0)
# # # # # # # # # # # # # # # #         + 0.10 * (h24 / 100.0)
# # # # # # # # # # # # # # # #         + 0.15 * (h48 / 200.0)
# # # # # # # # # # # # # # # #         + 0.35 * (h72 / 300.0)  # 72h ÔÇö priority cao nhß║ąt
# # # # # # # # # # # # # # # #         + 0.15 * (ate / 80.0)   # ATE ÔÇö beat 79.94
# # # # # # # # # # # # # # # #         + 0.15 * (cte / 94.0)   # CTE ÔÇö beat 93.58
# # # # # # # # # # # # # # # #     )
# # # # # # # # # # # # # # # #     return score * 100.0


# # # # # # # # # # # # # # # # def _beat_report(r: dict) -> str:
# # # # # # # # # # # # # # # #     """Tß║ío string b├ío c├ío so vß╗Ťi ST-Trans."""
# # # # # # # # # # # # # # # #     ade = r.get("ADE", float("inf"))
# # # # # # # # # # # # # # # #     h72 = r.get("72h", float("inf"))
# # # # # # # # # # # # # # # #     ate = r.get("ATE_mean", float("inf"))
# # # # # # # # # # # # # # # #     cte = r.get("CTE_mean", float("inf"))
