# # # # # # # # # # # # # # # #     if np.isfinite(ate) and ate < 79.94:  parts.append(f"ATEÔťů{ate:.1f}")
# # # # # # # # # # # # # # # #     if np.isfinite(cte) and cte < 93.58:  parts.append(f"CTEÔťů{cte:.1f}")
# # # # # # # # # # # # # # # #     if np.isfinite(h72) and h72 < 297.0:  parts.append(f"72hÔťů{h72:.1f}")
# # # # # # # # # # # # # # # #     return "­čĆć BEAT: " + " ".join(parts) if parts else ""


