# """
# scripts/train_flowmatching_v63.py
# Regime-aware Multi-Mode Anchor Flow Matching ÔÇö training script

# WHAT IS NEW vs v60/v61:
#   ÔÇó TCFlowMatchingV62 ÔÇö standalone, no ST-Trans checkpoint needed
#   ÔÇó Deterministic inference: t=0.60, argmax selector, speed-cosine fallback
#   ÔÇó Per-epoch log: oracle_ADE / mean_ADE / selected_ADE / ST-Trans gap
#   ÔÇó Multiplexed checkpoints: best_composite / best_raw / best_ema /
#                              best_fast / best_72h / best_cte / best_ate

# HOW TO RUN:
#   python scripts/train_flowmatching_v63.py \
#       --dataset_root TCND_vn \
#       --output_dir   runs/v63 \
#       --batch_size   32 \
#       --num_epochs   120 \
#       --n_modes      3 \
#       --use_amp \
#       --gpu_num 0

# EARLY-STOP GUIDE:
#   Watch oracle_ADE in the per-step log.
#   ep10:  oracle_ADE should be < 140 km  (generator learning)
#   ep20:  oracle_ADE should be < 125 km  (approaching ST-Trans)
#   ep30+: selected_ADE should drop toward oracle_ADE  (selector converging)
#   If ep10 oracle_ADE > 150: check lr, sigma_min, batch_size.
# """
