def _composite_score(r: dict) -> float:
    ade = r.get("ADE", float("inf"))
    h72 = r.get("72h", float("inf"))
    ate = r.get("ATE_mean", float("inf"))
    cte = r.get("CTE_mean", float("inf"))
    if not np.isfinite(ate): ate = ade * 0.46
    if not np.isfinite(cte): cte = ade * 0.53
    h12 = r.get("12h", float("inf"))
    h24 = r.get("24h", float("inf"))
    h48 = r.get("48h", float("inf"))
    return 100.0 * (
        0.05 * (ade / 136.0)
        + 0.10 * (h12 / 50.0)
        + 0.15 * (h24 / 100.0)
        + 0.20 * (h48 / 200.0)
        + 0.25 * (h72 / 300.0)
        + 0.13 * (ate / 80.0)
        + 0.12 * (cte / 94.0)
    )


def _beat_report(r: dict) -> str:
    parts = []
    for k, t in [("ADE", TARGETS["ADE"]), ("ATE_mean", TARGETS["ATE"]),
                  ("CTE_mean", TARGETS["CTE"]), ("72h", TARGETS["72h"]),
                  ("12h", TARGETS["12h"]), ("24h", TARGETS["24h"]),
                  ("48h", TARGETS["48h"])]:
        v = r.get(k, float("inf"))
        label = k.replace("_mean", "")
        if np.isfinite(v) and v < t:
            parts.append(f"{label}Ôťů{v:.1f}")
    return "­čĆć BEAT: " + " ".join(parts) if parts else ""


def _gap_vs_sttrans(r: dict) -> str:
    parts = []
    for k, ref in [("ADE", TARGETS["ADE"]), ("72h", TARGETS["72h"]),
                    ("ATE_mean", TARGETS["ATE"]), ("CTE_mean", TARGETS["CTE"])]:
        v = r.get(k, float("nan"))
        label = k.replace("_mean", "")
        if np.isfinite(v):
            gap = v - ref
            arrow = "Ôćô" if gap < 0 else "ÔćĹ"
            parts.append(f"{label}:{v:.0f}({arrow}{abs(gap):.0f})")
    return " | ".join(parts)


# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ
#  Coordinate helpers
# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ

def _norm_to_deg_local(arr: torch.Tensor) -> torch.Tensor:
    out = arr.clone()
    out[..., 0] = (arr[..., 0] * 50.0 + 1800.0) / 10.0
    out[..., 1] = (arr[..., 1] * 50.0) / 10.0
    return out


def _haversine_local(p1: torch.Tensor, p2: torch.Tensor) -> torch.Tensor:
    lat1 = torch.deg2rad(p1[..., 1]); lat2 = torch.deg2rad(p2[..., 1])
    dlat = lat2 - lat1; dlon = torch.deg2rad(p2[..., 0] - p1[..., 0])
    a = (torch.sin(dlat / 2).pow(2)
         + torch.cos(lat1) * torch.cos(lat2) * torch.sin(dlon / 2).pow(2))
    return 2.0 * R_EARTH * torch.asin(a.clamp(1e-12, 1 - 1e-12).sqrt())


def _compute_ate_cte_local(pred_deg, gt_deg):
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 2:
        z = pred_deg.new_zeros(1, pred_deg.shape[1])
        return z, z
    lon1 = torch.deg2rad(gt_deg[:T-1, :, 0]); lat1 = torch.deg2rad(gt_deg[:T-1, :, 1])
    lon2 = torch.deg2rad(gt_deg[1:T, :, 0]);  lat2 = torch.deg2rad(gt_deg[1:T, :, 1])
    lon3 = torch.deg2rad(pred_deg[1:T, :, 0]);lat3 = torch.deg2rad(pred_deg[1:T, :, 1])
    y_along = torch.sin(lon2-lon1)*torch.cos(lat2)
    x_along = torch.cos(lat1)*torch.sin(lat2) - torch.sin(lat1)*torch.cos(lat2)*torch.cos(lon2-lon1)
    bear_along = torch.atan2(y_along, x_along)
    y_err = torch.sin(lon3-lon2)*torch.cos(lat3)
    x_err = torch.cos(lat2)*torch.sin(lat3) - torch.sin(lat2)*torch.cos(lat3)*torch.cos(lon3-lon2)
    bear_err = torch.atan2(y_err, x_err)
    total = _haversine_local(pred_deg[1:T], gt_deg[1:T])
    angle = bear_err - bear_along
    return total * torch.cos(angle), total * torch.sin(angle)


# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ
#  Per-storm evaluation
# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ

_HORIZON_STEPS = {12: 1, 24: 3, 48: 7, 72: 11}


class PerStormAccumulator:
    def __init__(self):
        self.data = defaultdict(lambda: {
            "dists": [], "ates": [], "ctes": [],
            "step_dists": defaultdict(list), "n_seq": 0})

    def update(self, sid, dist, ate, cte):
        d = self.data[sid]
        d["dists"].extend(dist.mean(0).tolist())
        d["n_seq"] += dist.shape[1]
        for h, s in _HORIZON_STEPS.items():
            if s < dist.shape[0]:
                d["step_dists"][h].extend(dist[s].tolist())
        if ate is not None: d["ates"].extend(ate.abs().mean(0).tolist())
        if cte is not None: d["ctes"].extend(cte.abs().mean(0).tolist())

    def compute(self, sid) -> dict:
        d = self.data[sid]
        r = {"storm_id": sid, "n_seq": d["n_seq"],
             "ADE": float(np.mean(d["dists"])) if d["dists"] else float("nan"),
             "ATE": float(np.mean(d["ates"]))  if d["ates"]  else float("nan"),
             "CTE": float(np.mean(d["ctes"]))  if d["ctes"]  else float("nan")}
        for h in _HORIZON_STEPS:
            vals = d["step_dists"].get(h, [])
            r[f"{h}h"] = float(np.mean(vals)) if vals else float("nan")
        return r

    def compute_overall(self) -> dict:
        all_d, all_a, all_c = [], [], []
        step_all = defaultdict(list); n = 0
        for d in self.data.values():
            all_d.extend(d["dists"]); all_a.extend(d["ates"])
            all_c.extend(d["ctes"]); n += d["n_seq"]
            for h, vals in d["step_dists"].items():
                step_all[h].extend(vals)
        r = {"storm_id": "OVERALL", "n_seq": n,
             "ADE": float(np.mean(all_d)) if all_d else float("nan"),
             "ATE": float(np.mean(all_a)) if all_a else float("nan"),
             "CTE": float(np.mean(all_c)) if all_c else float("nan")}
        for h in _HORIZON_STEPS:
            vals = step_all.get(h, [])
            r[f"{h}h"] = float(np.mean(vals)) if vals else float("nan")
        return r


def _extract_storm_ids(batch) -> Optional[List[str]]:
    for idx in [2, 12, 14, 15]:
        if idx < len(batch):
            item = batch[idx]
            if isinstance(item, (list, tuple)) and item and isinstance(item[0], str):
                return list(item)
            if torch.is_tensor(item) and item.dtype == torch.long:
                return [str(x.item()) for x in item]
    return None


@torch.no_grad()
def evaluate_per_storm(model, loader, device, args,
                        ema_obj=None) -> List[dict]:
    backup = None
    if ema_obj is not None:
        try: backup = ema_obj.apply_to(model)
        except: pass

    model.eval()
    acc = PerStormAccumulator()

    for batch in loader:
        bl  = move(list(batch), device)
        sids = _extract_storm_ids(batch)
        pred, _, _ = model.sample(bl, num_ensemble=1, ddim_steps=1)
        gt   = bl[1]
        T    = min(pred.shape[0], gt.shape[0])
        B    = pred.shape[1]
        pd   = _norm_to_deg_local(pred[:T])
        gd   = _norm_to_deg_local(gt[:T])
        dist = _haversine_local(pd, gd)
        ate, cte = _compute_ate_cte_local(pd, gd)

        if sids and len(sids) == B:
            for b in range(B):
                acc.update(sids[b], dist[:, b:b+1],
                            ate[:, b:b+1] if ate is not None else None,
                            cte[:, b:b+1] if cte is not None else None)
        else:
            acc.update("STORM_ALL", dist, ate, cte)

    if backup is not None:
        try: ema_obj.restore(model, backup)
        except: pass

    storms = sorted(s for s in acc.data if s != "STORM_ALL")
    if not storms: storms = ["STORM_ALL"]
    results = [acc.compute(s) for s in storms]
    results.append(acc.compute_overall())
    return results


# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ
#  Helpers
# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ

def move(batch, device):
    out = list(batch)
    for i, x in enumerate(out):
        if torch.is_tensor(x): out[i] = x.to(device)
        elif isinstance(x, dict):
            out[i] = {k: v.to(device) if torch.is_tensor(v) else v
                      for k, v in x.items()}
    return out


def make_val_subset_loader(val_dataset, subset_size, batch_size,
                            collate_fn, num_workers):
    n   = len(val_dataset)
    idx = random.Random(42).sample(range(n), min(subset_size, n))
    return DataLoader(Subset(val_dataset, idx),
                      batch_size=batch_size, shuffle=False,
                      collate_fn=collate_fn, num_workers=0, drop_last=False)


def _get_ema_obj(model):
    m = model._orig_mod if hasattr(model, "_orig_mod") else model
    return getattr(m, "_ema", None)


def _call_ema_update(model):
    m = model._orig_mod if hasattr(model, "_orig_mod") else model
    if hasattr(m, "ema_update"): m.ema_update()


def _get_raw_model(model):
    return model._orig_mod if hasattr(model, "_orig_mod") else model


def _save_checkpoint(path, epoch, model, optimizer, scheduler,
                      saver, avg_t, avg_vl, metrics=None):
    m = _get_raw_model(model)
    ema = _get_ema_obj(model)
    ema_sd = None
    if ema is not None and hasattr(ema, "shadow"):
        try: ema_sd = {k: v.cpu().clone() for k, v in ema.shadow.items()}
        except: pass
    payload = {
        "epoch": epoch,
        "model_state_dict": m.state_dict(),
        "optimizer_state" : optimizer.state_dict(),
        "scheduler_state" : scheduler.state_dict(),
        "ema_shadow"      : ema_sd,
        "best_score": saver.best_score, "best_ade": saver.best_ade,
        "best_72h"  : saver.best_72h,  "best_ate"  : saver.best_ate,
        "best_cte"  : saver.best_cte,
        "train_loss": avg_t, "val_loss": avg_vl,
    }
    if metrics: payload.update(metrics)
    torch.save(payload, path)


