def _eval_batch(pred_norm, gt_norm):
    pred_d = denorm_torch(pred_norm)
    gt_d   = denorm_torch(gt_norm)
    if HAS_ATECTE:
        dist, ate, cte = haversine_and_atecte_torch(
            pred_d, gt_d, unit_01deg=True)
        return dist, ate, cte
    return haversine_km_torch(pred_d, gt_d), None, None


def _persistence_ade(batch_list, device):
    """Compute persistence forecast ADE for baseline logging."""
    import torch
    obs_t = batch_list[0]   # [T_obs, B, 2]
    gt    = batch_list[1]   # [T, B, 2]
    lp    = obs_t[-1]       # [B, 2]
    B, T  = lp.shape[0], gt.shape[0]

    if obs_t.shape[0] >= 3:
        vels  = obs_t[1:] - obs_t[:-1]
        n     = vels.shape[0]; alpha = 0.7
        w     = torch.tensor([alpha*(1-alpha)**i for i in range(n)],
                              dtype=torch.float, device=device).flip(0)
        lv    = (vels * (w/w.sum()).view(-1,1,1)).sum(0)
    elif obs_t.shape[0] >= 2:
        lv = obs_t[-1,:,:2] - obs_t[-2,:,:2]
    else:
        return float('nan')

    steps    = torch.arange(1, T+1, device=device).float()
    pred_abs = obs_t[-1,:,:2].unsqueeze(1) + lv.unsqueeze(1)*steps.view(1,-1,1)
    pred_abs = pred_abs.permute(1,0,2)   # [T,B,2]

    # Haversine
    def _n2d(x):
        return torch.stack([(x[...,0]*50+1800)/10,(x[...,1]*50)/10],dim=-1)
    def _hav(p1,p2):
        lat1=torch.deg2rad(p1[...,1]);lat2=torch.deg2rad(p2[...,1])
        dlat=torch.deg2rad(p2[...,1]-p1[...,1]);dlon=torch.deg2rad(p2[...,0]-p1[...,0])
        a=(torch.sin(dlat/2).pow(2)+torch.cos(lat1)*torch.cos(lat2)*torch.sin(dlon/2).pow(2))
        return 2*6371*torch.asin(a.clamp(1e-12,1-1e-12).sqrt())

    gt_abs = lp.unsqueeze(0) + gt[:T,:,:2]   # [T,B,2]
    pred_d = _n2d(pred_abs[:T]); gt_d = _n2d(gt_abs)
    return float(_hav(pred_d, gt_d).mean())


def evaluate_fast(model, loader, device, pred_len: int) -> dict:
    model.eval()
    acc = StepErrorAccumulator(pred_len)
    t0 = time.perf_counter(); n = 0
    persist_ades = []
    mode_counts  = [0, 0, 0]   # count how often each mode is selected

    with torch.no_grad():
        for batch in loader:
            bl   = move(list(batch), device)
            pred, _, all_preds = model.sample(bl, num_ensemble=1, ddim_steps=1)
            gt   = bl[1][:pred.shape[0]]
            dist, ate, cte = _eval_batch(pred, gt)
            acc.update(dist, ate_km=ate, cte_km=cte)

            # Persistence baseline
            p_ade = _persistence_ade(bl, device)
            if not (p_ade != p_ade):  # not nan
                persist_ades.append(p_ade)

            n += 1

    r = acc.compute()
    r["ms_per_batch"]    = (time.perf_counter() - t0) * 1e3 / max(n, 1)
    r["persistence_ADE"] = float(np.mean(persist_ades)) if persist_ades else float('nan')
    return r


def evaluate_full(model, loader, device, pred_len: int,
                   metrics_csv: str, epoch: int,
                   tag: str = "RAW", ema_obj=None) -> dict:
    backup = None
    if ema_obj is not None:
        try: backup = ema_obj.apply_to(model)
        except Exception as e:
            print(f"  ÔÜá  EMA apply failed: {e}")
            backup = None; ema_obj = None

    model.eval()
    acc = StepErrorAccumulator(pred_len)
    t0 = time.perf_counter(); n = 0
    with torch.no_grad():
        for batch in loader:
            bl   = move(list(batch), device)
            pred, _, _ = model.sample(bl, num_ensemble=1, ddim_steps=1)
            gt   = bl[1][:pred.shape[0]]
            dist, ate, cte = _eval_batch(pred, gt)
            acc.update(dist, ate_km=ate, cte_km=cte)
            n += 1

    r = acc.compute(); elapsed = time.perf_counter() - t0
    score = _composite_score(r)

    def _v(k): return r.get(k, float("nan"))
    def _m(v, t): return "Ôťů" if np.isfinite(v) and v < t else "ÔŁî"

    print(f"\n{'='*68}")
    print(f"  [{tag} ep={epoch}  {elapsed:.0f}s  {n} batches]")
    print(f"  ADE={_v('ADE'):.1f}{_m(_v('ADE'),TARGETS['ADE'])}  "
          f"12h={_v('12h'):.0f}{_m(_v('12h'),TARGETS['12h'])}  "
          f"24h={_v('24h'):.0f}{_m(_v('24h'),TARGETS['24h'])}  "
          f"48h={_v('48h'):.0f}{_m(_v('48h'),TARGETS['48h'])}  "
          f"72h={_v('72h'):.0f}{_m(_v('72h'),TARGETS['72h'])}")
    if np.isfinite(_v("ATE_mean")):
        print(f"  ATE={_v('ATE_mean'):.1f}{_m(_v('ATE_mean'),TARGETS['ATE'])}  "
              f"CTE={_v('CTE_mean'):.1f}{_m(_v('CTE_mean'),TARGETS['CTE'])}")
    print(f"  vs ST-Trans: {_gap_vs_sttrans(r)}")
    beat = _beat_report(r)
    if beat: print(f"  {beat}")
    print(f"  Score={score:.2f}")
    print(f"{'='*68}\n")

    from datetime import datetime as _dt
    dm = DatasetMetrics(
        ade=_v("ADE") if np.isfinite(_v("ADE")) else 0.0,
        fde=_v("FDE") if np.isfinite(_v("FDE")) else 0.0,
        ugde_12h=_v("12h") if np.isfinite(_v("12h")) else 0.0,
        ugde_24h=_v("24h") if np.isfinite(_v("24h")) else 0.0,
        ugde_48h=_v("48h") if np.isfinite(_v("48h")) else 0.0,
        ugde_72h=_v("72h") if np.isfinite(_v("72h")) else 0.0,
        ate_abs_mean=_v("ATE_mean") if np.isfinite(_v("ATE_mean")) else 0.0,
        cte_abs_mean=_v("CTE_mean") if np.isfinite(_v("CTE_mean")) else 0.0,
        n_total=r.get("n_samples", 0),
        timestamp=_dt.now().strftime("%Y%m%d_%H%M%S"),
    )
    save_metrics_csv(dm, metrics_csv, tag=f"val_{tag}_ep{epoch:03d}")

    if backup is not None:
        try: ema_obj.restore(model, backup)
        except Exception as e: print(f"  ÔÜá  EMA restore failed: {e}")
    return r


