class MultiplexedBestSaver:
    def __init__(self, patience: int = 35, tol: float = 0.0):
        self.patience = patience; self.tol = tol
        self.counter  = 0; self.early_stop = False
        self.best_score = self.best_ade = self.best_72h = \
            self.best_ate = self.best_cte = \
            self.best_48h = self.best_24h = self.best_12h = float("inf")
        self.best_raw_score = self.best_ema_score = self.best_fast_score = float("inf")

    def update_per_metric(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        ade = r.get("ADE", float("inf"))
        h72 = r.get("72h", float("inf"))
        ate = r.get("ATE_mean", float("inf"))
        cte = r.get("CTE_mean", float("inf"))
        improved = False
        for v, attr, fname, extra in [
            (ade, "best_ade", "best_ade.pth", {"ade": ade}),
            (h72, "best_72h", "best_72h.pth", {"h72": h72}),
            (ate, "best_ate", "best_ate.pth", {"ate": ate}),
            (cte, "best_cte", "best_cte.pth", {"cte": cte}),
        ]:
            if v < getattr(self, attr):
                setattr(self, attr, v); improved = True
                _save_checkpoint(os.path.join(out_dir, fname),
                                  epoch, model, opt, sched, self, tl, vl, extra)
        for v, a in [(r.get("48h",float("inf")), "best_48h"),
                      (r.get("24h",float("inf")), "best_24h"),
                      (r.get("12h",float("inf")), "best_12h")]:
            if v < getattr(self, a): setattr(self, a, v); improved = True
        return improved

    def _save_track(self, score, attr, fname, r, model, out_dir,
                     epoch, opt, sched, tl, vl, label):
        if score < getattr(self, attr) - self.tol:
            setattr(self, attr, score)
            _save_checkpoint(os.path.join(out_dir, fname),
                              epoch, model, opt, sched, self, tl, vl,
                              {"score": score,
                               "ade": r.get("ADE", float("nan")),
                               "h72": r.get("72h", float("nan"))})
            print(f"  Ôťů Best {label} score={score:.2f}  "
                  f"ADE={r.get('ADE',float('nan')):.1f}  "
                  f"72h={r.get('72h',float('nan')):.0f}  (ep {epoch})")

    def update_raw(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        self._save_track(_composite_score(r), "best_raw_score",
                          "best_raw.pth", r, model, out_dir,
                          epoch, opt, sched, tl, vl, "RAW")

    def update_ema(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        self._save_track(_composite_score(r), "best_ema_score",
                          "best_ema.pth", r, model, out_dir,
                          epoch, opt, sched, tl, vl, "EMA")

    def update_fast(self, r, model, out_dir, epoch, opt, sched, tl, vl):
        self._save_track(_composite_score(r), "best_fast_score",
                          "best_fast.pth", r, model, out_dir,
                          epoch, opt, sched, tl, vl, "FAST")

    def update_composite(self, r, model, out_dir, epoch, opt, sched,
                          tl, vl, min_epochs: int = 25):
        score = _composite_score(r)
        ade   = r.get("ADE", float("inf"))
        h72   = r.get("72h", float("inf"))
        ate   = r.get("ATE_mean", float("inf"))
        cte   = r.get("CTE_mean", float("inf"))

        if score < self.best_score - self.tol:
            self.best_score = score; self.counter = 0
            _save_checkpoint(os.path.join(out_dir, "best_composite.pth"),
                              epoch, model, opt, sched, self, tl, vl,
                              {"composite": score, "ade": ade,
                               "h72": h72, "ate": ate, "cte": cte})
            print(f"  Ôťů Best COMPOSITE={score:.2f}  ADE={ade:.1f}  "
                  f"72h={h72:.0f}  ATE={ate:.1f}  CTE={cte:.1f}  (ep {epoch})")
        else:
            self.counter += 1
            print(f"  No improvement {self.counter}/{self.patience}"
                  f"  (best={self.best_score:.2f} cur={score:.2f})"
                  f"  72h={h72:.0f}Ôćô{self.best_72h:.0f}")

        if epoch >= min_epochs and self.counter >= self.patience:
            self.early_stop = True


