def save_metrics_table_csv(results, csv_path, model_name, split,
                            epoch=None, train_loss=None, val_loss=None):
    os.makedirs(os.path.dirname(os.path.abspath(csv_path)), exist_ok=True)
    ts = datetime.now().strftime("%Y%m%d%H%M%S")
    fields = ["timestamp","split","epoch","model_type","train_loss","val_loss",
              "ADE_km","12h_km","24h_km","48h_km","72h_km","ATE_abs","CTE_abs",
              "storm_id","n_seq","beat_ADE","beat_72h","beat_ATE","beat_CTE",
              "beat_12h","beat_24h","beat_48h","composite_score"]
    write_hdr = not os.path.exists(csv_path)
    with open(csv_path, "a", newline="") as fh:
        w = csv.DictWriter(fh, fieldnames=fields)
        if write_hdr: w.writeheader()
        for r in results:
            def _f(k): v=r.get(k,float("nan")); return f"{v:.2f}" if np.isfinite(v) else "nan"
            def _b(k): v=r.get(k,float("nan")); return "YES" if np.isfinite(v) and v < TARGETS.get(k,float("inf")) else "NO"
            score = _composite_score({"ADE": r.get("ADE",float("inf")),
                                       "72h": r.get("72h",float("inf")),
                                       "48h": r.get("48h",float("inf")),
                                       "24h": r.get("24h",float("inf")),
                                       "12h": r.get("12h",float("inf")),
                                       "ATE_mean": r.get("ATE",float("inf")),
                                       "CTE_mean": r.get("CTE",float("inf"))})
            w.writerow({
                "timestamp": ts, "split": split,
                "epoch": epoch if epoch is not None else "",
                "model_type": model_name,
                "train_loss": f"{train_loss:.4f}" if train_loss else "",
                "val_loss":   f"{val_loss:.4f}"   if val_loss   else "",
                "ADE_km": _f("ADE"), "12h_km": _f("12h"), "24h_km": _f("24h"),
                "48h_km": _f("48h"), "72h_km": _f("72h"),
                "ATE_abs": _f("ATE"), "CTE_abs": _f("CTE"),
                "storm_id": r.get("storm_id",""), "n_seq": r.get("n_seq",""),
                "beat_ADE": _b("ADE"), "beat_72h": _b("72h"),
                "beat_ATE": _b("ATE"), "beat_CTE": _b("CTE"),
                "beat_12h": _b("12h"), "beat_24h": _b("24h"), "beat_48h": _b("48h"),
                "composite_score": f"{score:.2f}",
            })


def _print_storm_table(results, model_name):
    print(f"\n{'='*108}")
    print(f"  Per-Storm  |  {model_name}")
    print(f"  {'Storm':<14} {'N':>5}  {'ADE':>8}  {'12h':>8}  {'24h':>8}  {'48h':>8}  {'72h':>8}  {'ATE':>8}  {'CTE':>8}")
    print(f"  {'-'*104}")

    def _v(r, k):
        v = r.get(k, float("nan")); t = TARGETS.get(k)
        s = f"{v:>7.1f}" if np.isfinite(v) else "    nan"
        if t and np.isfinite(v): s += "Ôťů" if v < t else "ÔŁî"
        else: s += "  "
        return s

    for r in results:
        sid = r["storm_id"]
        if sid == "OVERALL":
            print(f"  {'ÔöÇ'*104}")
            pre = f"  {'­čôŐ OVERALL':<14}"
        else:
            pre = f"  ­čîÇ {sid:<11}"
        print(f"{pre} {r['n_seq']:>5}  "
              f"{_v(r,'ADE')}  {_v(r,'12h')}  {_v(r,'24h')}  "
              f"{_v(r,'48h')}  {_v(r,'72h')}  {_v(r,'ATE')}  {_v(r,'CTE')}")

    overall = results[-1]
    beats = [f"{k}={overall.get(k,float('nan')):.1f}Ôťů"
             for k in ["ADE","12h","24h","48h","72h","ATE","CTE"]
             if np.isfinite(overall.get(k, float("nan")))
             and overall.get(k) < TARGETS.get(k, float("inf"))]
    if beats: print(f"  ­čĆć BEAT: {' | '.join(beats)}")
    print(f"{'='*108}\n")


# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ
#  Args
# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ

def get_args():
    p = argparse.ArgumentParser(
        formatter_class=argparse.ArgumentDefaultsHelpFormatter)
    p.add_argument("--dataset_root",    default="TCND_vn",    type=str)
    p.add_argument("--obs_len",         default=8,            type=int)
    p.add_argument("--pred_len",        default=12,           type=int)
    p.add_argument("--batch_size",      default=32,           type=int)
    p.add_argument("--num_epochs",      default=120,          type=int)
    p.add_argument("--g_learning_rate", default=1e-4,         type=float)
    p.add_argument("--weight_decay",    default=1e-3,         type=float)
    p.add_argument("--warmup_epochs",   default=5,            type=int)
    p.add_argument("--grad_clip",       default=1.0,          type=float)
    p.add_argument("--patience",        default=35,           type=int)
    p.add_argument("--min_epochs",      default=25,           type=int)
    p.add_argument("--n_modes",         default=3,            type=int)
    p.add_argument("--use_amp",         action="store_true")
    p.add_argument("--num_workers",     default=2,            type=int)
    p.add_argument("--sigma_min",            default=0.02,    type=float)
    p.add_argument("--ctx_noise_scale",      default=0.01,    type=float)
    p.add_argument("--initial_sample_sigma", default=0.03,    type=float)
    # These are kept for API compatibility with the training loop; v62 uses 1/1
    p.add_argument("--ode_steps_val",   default=1,            type=int)
    p.add_argument("--val_ensemble",    default=1,            type=int)
    p.add_argument("--fast_ensemble",   default=1,            type=int)
    p.add_argument("--val_freq",        default=3,            type=int)
    p.add_argument("--val_subset_size", default=500,          type=int)
    p.add_argument("--use_ema",         action="store_true",  default=True)
    p.add_argument("--ema_decay",       default=0.995,        type=float)
    p.add_argument("--output_dir",  default="runs/v63",              type=str)
    p.add_argument("--metrics_csv", default="metrics_v63.csv",       type=str)
    p.add_argument("--table_csv",   default="metrics_table_v63.csv", type=str)
    p.add_argument("--predict_csv", default="predictions_v62.csv",   type=str)
    p.add_argument("--gpu_num",     default="0",                      type=str)
    p.add_argument("--delim",       default=" ")
    p.add_argument("--skip",        default=1,   type=int)
    p.add_argument("--min_ped",     default=1,   type=int)
    p.add_argument("--threshold",   default=0.002, type=float)
    p.add_argument("--other_modal", default="gph")
    p.add_argument("--test_year",   default=None, type=int)
    p.add_argument("--resume",       default=None, type=str)
    p.add_argument("--resume_epoch", default=None, type=int)
    p.add_argument("--eval_test_after_train", action="store_true", default=True)
    p.add_argument("--test_storm_csv", default=None, type=str)
    return p.parse_args()


# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ
#  MAIN
# ÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉÔĽÉ

def main(args):
    if torch.cuda.is_available():
        os.environ["CUDA_VISIBLE_DEVICES"] = str(args.gpu_num)
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    os.makedirs(args.output_dir, exist_ok=True)
    metrics_csv = os.path.join(args.output_dir, args.metrics_csv)
    table_csv   = os.path.join(args.output_dir, args.table_csv)

    print("=" * 80)
    print("  TC-FlowMatching v62  ÔÇö  Regime-aware Multi-Mode Anchor FM")
    print(f"  K modes         : {args.n_modes}")
    print(f"  Inference       : t=0.60 fixed, argmax selector, speed-cosine fallback")
    print(f"  Loss            : anchor(2.0) + fm(1.5) + rank(0.30) + regime(0.15)")
    print(f"  ST-Trans target : ADE<{TARGETS['ADE']} | 72h<{TARGETS['72h']}")
    print(f"                    ATE<{TARGETS['ATE']} | CTE<{TARGETS['CTE']}")
    print("  KEY LOG: watch oracle_ADE ÔÇö must be < 140 by ep10")
    print("=" * 80)

    train_dataset, train_loader = data_loader(
        args, {"root": args.dataset_root, "type": "train"}, test=False)
    val_dataset,   val_loader   = data_loader(
        args, {"root": args.dataset_root, "type": "val"},   test=True)

    from Model.data.trajectoriesWithMe_unet_training import seq_collate
    val_subset_loader = make_val_subset_loader(
        val_dataset, args.val_subset_size, args.batch_size,
        seq_collate, args.num_workers)

    print(f"  train: {len(train_dataset)} seqs  ({len(train_loader)} batches)")
    print(f"  val  : {len(val_dataset)} seqs")

    model = TCFlowMatchingV63(
        pred_len=args.pred_len, obs_len=args.obs_len,
        sigma_min=args.sigma_min, n_train_ens=1,
        ctx_noise_scale=args.ctx_noise_scale,
        initial_sample_sigma=args.initial_sample_sigma,
        use_ema=args.use_ema, ema_decay=args.ema_decay,
        n_modes=args.n_modes,
    ).to(device)

    n_params = sum(p.numel() for p in model.parameters() if p.requires_grad)
    print(f"  params: {n_params:,}")
    model.init_ema()

    optimizer = optim.AdamW(model.parameters(),
                             lr=args.g_learning_rate,
                             weight_decay=args.weight_decay)
    saver  = MultiplexedBestSaver(patience=args.patience)
    scaler = GradScaler("cuda", enabled=args.use_amp)

    steps_per_epoch = len(train_loader)
    total_steps     = steps_per_epoch * args.num_epochs
    warmup_steps    = steps_per_epoch * args.warmup_epochs
    scheduler = get_cosine_schedule_with_warmup(
        optimizer, warmup_steps, total_steps, min_lr=1e-6)

    start_epoch = 0
    _ckpt_sched = None

    if args.resume and os.path.exists(args.resume):
        print(f"  Loading: {args.resume}")
        ckpt = torch.load(args.resume, map_location=device)
        m    = _get_raw_model(model)
        miss, unexp = m.load_state_dict(ckpt["model_state_dict"], strict=False)
        if miss:  print(f"  ÔÜá  Missing keys: {len(miss)}")
        if unexp: print(f"  ÔÜá  Unexpected keys: {len(unexp)}")
        if "ema_shadow" in ckpt and ckpt["ema_shadow"] is not None:
            ema = _get_ema_obj(model)
            if ema:
                for k, v in ckpt["ema_shadow"].items():
                    if k in ema.shadow: ema.shadow[k].copy_(v.to(device))
                print("  EMA shadow: loaded")
        if "optimizer_state" in ckpt:
            try:
                optimizer.load_state_dict(ckpt["optimizer_state"])
                for st in optimizer.state.values():
                    for k, v in st.items():
                        if torch.is_tensor(v): st[k] = v.to(device)
            except Exception as e: print(f"  ÔÜá  Opt restore: {e}")
        _ckpt_sched = ckpt.get("scheduler_state", None)
        for attr in ("best_score", "best_ade", "best_72h", "best_ate", "best_cte"):
            if attr in ckpt: setattr(saver, attr, ckpt[attr])
        start_epoch = (args.resume_epoch if args.resume_epoch is not None
                       else ckpt.get("epoch", 0) + 1)
        print(f"  Ôćĺ Resuming from epoch {start_epoch}")

    try:
        model = torch.compile(model, mode="reduce-overhead")
        print("  torch.compile: enabled")
    except Exception:
        pass

    if _ckpt_sched is not None:
        try: scheduler.load_state_dict(_ckpt_sched)
        except Exception as e:
            print(f"  ÔÜá  Scheduler restore: {e}")
            for _ in range(start_epoch * steps_per_epoch): scheduler.step()
    elif start_epoch > 0:
        for _ in range(start_epoch * steps_per_epoch): scheduler.step()

    print("=" * 80)
    print(f"  TRAINING  ({steps_per_epoch} steps/epoch, start={start_epoch})")
    print("=" * 80)

    epoch_times = []; train_start = time.perf_counter()
    last_avg_t = 0.0; last_avg_vl = 0.0

    for epoch in range(start_epoch, args.num_epochs):
        model.train()
        sum_loss = 0.0; t0 = time.perf_counter()

        for i, batch in enumerate(train_loader):
            bl = move(list(batch), device)

            with autocast(device_type="cuda", enabled=args.use_amp):
                bd = model.get_loss_breakdown(bl, epoch=epoch)

            optimizer.zero_grad()
            scaler.scale(bd["total"]).backward()
            scaler.unscale_(optimizer)
            torch.nn.utils.clip_grad_norm_(model.parameters(), args.grad_clip)

            scale_before = scaler.get_scale()
            scaler.step(optimizer); scaler.update()
            if scaler.get_scale() >= scale_before: scheduler.step()
            _call_ema_update(model)

            sum_loss += bd["total"].item()

            if i % 20 == 0:
                lr = optimizer.param_groups[0]["lr"]
                print(
                    f"  [{epoch:>3}][{i:>3}/{steps_per_epoch}]"
                    f"  tot={bd['total'].item():.3f}"
                    f"  dpe={bd.get('dpe_oracle',   0):.3f}"
                    f"  dir={bd.get('directional',  0):.3f}"
                    f"  tmp={bd.get('temporal',     0):.3f}"
                    f"  rank={bd.get('rank_l',      0):.4f}(w={bd.get('rank_w',0):.2f})"
                    f"  gap={bd.get('selector_gap', 0):.1f}km"   # KEY: selector learning
                    f"  oracle={bd.get('oracle_ade', 0):.1f}km"  # KEY: generator
                    f"  mean={bd.get('mean_ade',    0):.1f}km"
                    f"  cte={bd.get('cte_km',       0):.1f}km"
                    f"  consist={bd.get('consist_l', 0):.4f}"
                    f"  fm={bd.get('fm_mse',         0):.4f}"
                    f"  lr={lr:.2e}"
                )

        ep_s  = time.perf_counter() - t0; epoch_times.append(ep_s)
        avg_t = sum_loss / steps_per_epoch

        # Val loss
        model.eval(); val_loss = 0.0
        with torch.no_grad():
            for batch in val_loader:
                bl_v = move(list(batch), device)
                with autocast(device_type="cuda", enabled=args.use_amp):
                    val_loss += model.get_loss(bl_v, epoch=epoch).item()
        avg_vl = val_loss / len(val_loader)
        last_avg_t = avg_t; last_avg_vl = avg_vl
        print(f"  Epoch {epoch:>3}  train={avg_t:.4f}  val={avg_vl:.4f}  {ep_s:.0f}s")

        # Fast eval every epoch
        m_fast = evaluate_fast(model, val_subset_loader, device, args.pred_len)
        fast_score = _composite_score(m_fast)

        def _ind(v, t): return "­čÄ»" if np.isfinite(v) and v < t else "ÔŁî"
        p_ade = m_fast.get('persistence_ADE', float('nan'))
        print(
            f"  [FAST ep{epoch}]"
            f"  persist={p_ade:.0f}km"           # baseline
            f"  ADE={m_fast.get('ADE',float('nan')):.1f}{_ind(m_fast.get('ADE',1e9),172.68)}"
            f"  12h={m_fast.get('12h',float('nan')):.0f}{_ind(m_fast.get('12h',1e9),65.42)}"
            f"  24h={m_fast.get('24h',float('nan')):.0f}{_ind(m_fast.get('24h',1e9),104.67)}"
            f"  48h={m_fast.get('48h',float('nan')):.0f}{_ind(m_fast.get('48h',1e9),205.10)}"
            f"  72h={m_fast.get('72h',float('nan')):.0f}{_ind(m_fast.get('72h',1e9),321.39)}"
            f"  ATE={m_fast.get('ATE_mean',float('nan')):.1f}{_ind(m_fast.get('ATE_mean',1e9),142.21)}"
            f"  CTE={m_fast.get('CTE_mean',float('nan')):.1f}{_ind(m_fast.get('CTE_mean',1e9),42.04)}"
            f"  score={fast_score:.2f}"
        )
        print(f"  vs ST-Trans: {_gap_vs_sttrans(m_fast)}")
        saver.update_fast(m_fast, model, args.output_dir, epoch,
                           optimizer, scheduler, avg_t, avg_vl)

        # Full val every val_freq epochs
        if epoch % args.val_freq == 0:
            ema = _get_ema_obj(model)
            try:
                r_raw = evaluate_full(model, val_loader, device, args.pred_len,
                                       metrics_csv, epoch, tag="RAW")
                saver.update_raw(r_raw, model, args.output_dir, epoch,
                                  optimizer, scheduler, avg_t, avg_vl)
                saver.update_per_metric(r_raw, model, args.output_dir, epoch,
                                         optimizer, scheduler, avg_t, avg_vl)

                r_use = r_raw
                if ema is not None and epoch >= 5:
                    r_ema = evaluate_full(model, val_loader, device,
                                          args.pred_len, metrics_csv, epoch,
                                          tag="EMA", ema_obj=ema)
                    saver.update_ema(r_ema, model, args.output_dir, epoch,
                                      optimizer, scheduler, avg_t, avg_vl)
                    if _composite_score(r_ema) < _composite_score(r_raw):
                        r_use = r_ema

                saver.update_composite(r_use, model, args.output_dir, epoch,
                                        optimizer, scheduler, avg_t, avg_vl,
                                        min_epochs=args.min_epochs)

                save_metrics_table_csv(
                    [{"storm_id": "val_overall", "n_seq": 0,
                      "ADE": r_use.get("ADE", float("nan")),
                      "12h": r_use.get("12h", float("nan")),
                      "24h": r_use.get("24h", float("nan")),
                      "48h": r_use.get("48h", float("nan")),
                      "72h": r_use.get("72h", float("nan")),
                      "ATE": r_use.get("ATE_mean", float("nan")),
                      "CTE": r_use.get("CTE_mean", float("nan"))}],
                    table_csv, "FM-v63", split="val",
                    epoch=epoch, train_loss=avg_t, val_loss=avg_vl)

            except Exception as e:
                print(f"  ÔÜá  Full val failed: {e}")
                import traceback; traceback.print_exc()

        if epoch % 10 == 0 or epoch == args.num_epochs - 1:
            _save_checkpoint(
                os.path.join(args.output_dir, f"ckpt_ep{epoch:03d}.pth"),
                epoch, model, optimizer, scheduler, saver, avg_t, avg_vl,
                {"ade": m_fast.get("ADE", float("nan")),
                 "h72": m_fast.get("72h", float("nan")),
                 "ate": m_fast.get("ATE_mean", float("nan")),
                 "cte": m_fast.get("CTE_mean", float("nan"))})

        if epoch % 10 == 9:
            avg_ep    = sum(epoch_times) / len(epoch_times)
            remaining = (args.num_epochs - epoch - 1) * avg_ep / 3600
            elapsed_h = (time.perf_counter() - train_start) / 3600
            print(f"  ÔĆ▒  {elapsed_h:.1f}h elapsed | ~{remaining:.1f}h remaining")
            print(f"  ­čôŐ composite={saver.best_score:.2f}  raw={saver.best_raw_score:.2f}  "
                  f"ema={saver.best_ema_score:.2f}")
            print(f"      72h={saver.best_72h:.0f}  ATE={saver.best_ate:.1f}  "
                  f"CTE={saver.best_cte:.1f}")

        if saver.early_stop:
            print(f"  ÔŤö Early stopping at epoch {epoch}")
            break

    total_h = (time.perf_counter() - train_start) / 3600
    print(f"\n  Best composite: ADE={saver.best_ade:.1f}  72h={saver.best_72h:.0f}"
          f"  ATE={saver.best_ate:.1f}  CTE={saver.best_cte:.1f}")
    print(f"  Total: {total_h:.2f}h")

    # ÔöÇÔöÇ Post-training test evaluation ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    if args.eval_test_after_train:
        print("\n" + "=" * 80)
        print("  POST-TRAINING: Test evaluation")
        print("=" * 80)

        try:
            test_dataset, test_loader = data_loader(
                args, {"root": args.dataset_root, "type": "test"}, test=True)
            print(f"  test: {len(test_dataset)} seqs  ({len(test_loader)} batches)")
        except Exception as e:
            print(f"  ÔÜá  Test set unavailable: {e} ÔÇö using val")
            test_loader = val_loader

        ckpt_candidates = [
            ("best_composite.pth", "v62-COMPOSITE"),
            ("best_raw.pth",       "v62-RAW"),
            ("best_ema.pth",       "v62-EMA"),
            ("best_fast.pth",      "v62-FAST"),
            ("best_72h.pth",       "v62-72h"),
            ("best_cte.pth",       "v62-CTE"),
        ]

        all_results: Dict[str, dict] = {}

        for ckpt_name, label in ckpt_candidates:
            ckpt_path = os.path.join(args.output_dir, ckpt_name)
            if not os.path.exists(ckpt_path):
                print(f"  skip {ckpt_name}")
                continue

            try:
                ckpt = torch.load(ckpt_path, map_location=device)
                m    = _get_raw_model(model)
                m.load_state_dict(ckpt["model_state_dict"], strict=False)
                ema  = _get_ema_obj(model)
                if ema and ckpt.get("ema_shadow"):
                    for k, v in ckpt["ema_shadow"].items():
                        if k in ema.shadow: ema.shadow[k].copy_(v.to(device))
            except Exception as e:
                print(f"  ÔÜá  Load {ckpt_name}: {e}"); continue

            print(f"\n  ÔöÇÔöÇ {label} (RAW)")
            r_raw = evaluate_per_storm(model, test_loader, device, args)
            all_results[f"{label}-RAW"] = r_raw[-1]
            ovr = r_raw[-1]
            print(f"    ADE={ovr.get('ADE',float('nan')):.1f}  "
                  f"72h={ovr.get('72h',float('nan')):.1f}  "
                  f"ATE={ovr.get('ATE',float('nan')):.1f}  "
                  f"CTE={ovr.get('CTE',float('nan')):.1f}")

            ema = _get_ema_obj(model)
            if ema and ckpt.get("ema_shadow"):
                print(f"  ÔöÇÔöÇ {label} (EMA)")
                r_ema = evaluate_per_storm(model, test_loader, device,
                                            args, ema_obj=ema)
                all_results[f"{label}-EMA"] = r_ema[-1]
                ovr = r_ema[-1]
                print(f"    ADE={ovr.get('ADE',float('nan')):.1f}  "
                      f"72h={ovr.get('72h',float('nan')):.1f}  "
                      f"ATE={ovr.get('ATE',float('nan')):.1f}  "
                      f"CTE={ovr.get('CTE',float('nan')):.1f}")

        if all_results:
            print("\n" + "ÔöÇ" * 80)
            print(f"  {'Model':<28}  {'ADE':>6}  {'72h':>6}  {'ATE':>6}  {'CTE':>6}  Beat?")
            print(f"  {'ST-Trans (target)':<28}  "
                  f"{TARGETS['ADE']:>6.1f}  {TARGETS['72h']:>6.1f}  "
                  f"{TARGETS['ATE']:>6.1f}  {TARGETS['CTE']:>6.1f}  REF")
            for name, res in sorted(all_results.items()):
                ade = res.get("ADE", float("nan"))
                h72 = res.get("72h", float("nan"))
                ate = res.get("ATE", float("nan"))
                cte = res.get("CTE", float("nan"))
                beat = ("Ôťů" if np.isfinite(ade) and ade < TARGETS["ADE"]
                                and np.isfinite(h72) and h72 < TARGETS["72h"]
                         else "ÔŁî")
                print(f"  {name:<28}  {ade:>6.1f}  {h72:>6.1f}  "
                      f"{ate:>6.1f}  {cte:>6.1f}  {beat}")

            def _key(item):
                _, r = item
                return (r.get("72h", 1e9) if np.isfinite(r.get("72h", 1e9)) else 1e9,
                        r.get("ADE", 1e9) if np.isfinite(r.get("ADE", 1e9)) else 1e9)

            winner_name, winner_res = min(all_results.items(), key=_key)
            print("ÔöÇ" * 80)
            print(f"  ­čĆć WINNER: {winner_name}")
            print(f"     ADE={winner_res.get('ADE',float('nan')):.1f}  "
                  f"72h={winner_res.get('72h',float('nan')):.1f}  "
                  f"ATE={winner_res.get('ATE',float('nan')):.1f}  "
                  f"CTE={winner_res.get('CTE',float('nan')):.1f}")
            print("ÔöÇ" * 80)

            # Load winner and do full per-storm evaluation
            ckpt_path_winner = None
            for cn, lbl in ckpt_candidates:
                if lbl in winner_name:
                    ckpt_path_winner = os.path.join(args.output_dir, cn)
                    break

            if ckpt_path_winner and os.path.exists(ckpt_path_winner):
                ckpt_w = torch.load(ckpt_path_winner, map_location=device)
                m = _get_raw_model(model)
                m.load_state_dict(ckpt_w["model_state_dict"], strict=False)
                ema_w = None
                if "EMA" in winner_name:
                    ema_w = _get_ema_obj(model)
                    if ema_w and ckpt_w.get("ema_shadow"):
                        for k, v in ckpt_w["ema_shadow"].items():
                            if k in ema_w.shadow: ema_w.shadow[k].copy_(v.to(device))

                results_final = evaluate_per_storm(
                    model, test_loader, device, args, ema_obj=ema_w)
                _print_storm_table(results_final, winner_name)

                save_metrics_table_csv(
                    results_final, table_csv, winner_name,
                    split="test", epoch=ckpt_w.get("epoch", 0),
                    train_loss=last_avg_t, val_loss=last_avg_vl)

                # Save per-storm CSV
                storm_csv = args.test_storm_csv or os.path.join(
                    args.output_dir, "test_storm_v62.csv")
                os.makedirs(os.path.dirname(os.path.abspath(storm_csv)), exist_ok=True)
                ts = datetime.now().strftime("%Y%m%d_%H%M%S")
                fields = ["timestamp","model","storm_id","n_seq",
                          "ADE","12h","24h","48h","72h","ATE","CTE",
                          "beat_ADE","beat_72h","beat_ATE","beat_CTE",
                          "gap_ADE","gap_72h"]
                with open(storm_csv, "w", newline="") as fh:
                    w = csv.DictWriter(fh, fieldnames=fields)
                    w.writeheader()
                    for r in results_final:
                        def _f(k): return f"{r.get(k,float('nan')):.2f}"
                        def _b(k):
                            v = r.get(k, float("nan"))
                            return "YES" if np.isfinite(v) and v < TARGETS.get(k, 1e9) else "NO"
                        def _g(k, ref):
                            v = r.get(k, float("nan"))
                            return f"{v-ref:.1f}" if np.isfinite(v) else "nan"
                        w.writerow({
                            "timestamp": ts, "model": winner_name,
                            "storm_id": r["storm_id"], "n_seq": r["n_seq"],
                            "ADE": _f("ADE"), "12h": _f("12h"), "24h": _f("24h"),
                            "48h": _f("48h"), "72h": _f("72h"),
                            "ATE": _f("ATE"),  "CTE": _f("CTE"),
                            "beat_ADE": _b("ADE"), "beat_72h": _b("72h"),
                            "beat_ATE": _b("ATE"), "beat_CTE": _b("CTE"),
                            "gap_ADE": _g("ADE", TARGETS["ADE"]),
                            "gap_72h": _g("72h", TARGETS["72h"]),
                        })
                print(f"  Per-storm CSV: {storm_csv}")

                overall = results_final[-1]
                print(f"\n{'ÔĽÉ'*70}")
                print(f"  FINAL TEST  ({winner_name})  | v62")
                print(f"  {'ÔöÇ'*66}")
                all_beat = True
                for key, label_r, target in [
                    ("12h",  "12h (lead 12h)",     TARGETS["12h"]),
                    ("24h",  "24h (lead 24h)",     TARGETS["24h"]),
                    ("48h",  "48h (lead 48h)",     TARGETS["48h"]),
                    ("72h",  "72h (lead 72h)",     TARGETS["72h"]),
                    ("ADE",  "ADE (overall)",      TARGETS["ADE"]),
                    ("ATE",  "ATE (along-track)",  TARGETS["ATE"]),
                    ("CTE",  "CTE (cross-track)",  TARGETS["CTE"]),
                ]:
                    v   = overall.get(key, float("nan"))
                    ref = TARGETS.get(key, float("nan"))
                    if np.isfinite(v):
                        mark = "Ôťů BEAT!" if v < target else f"ÔŁî  (target:{target:.0f})"
                        gap  = f"  [gap vs ST-Trans: {v-ref:+.1f}]"
                        if v >= target: all_beat = False
                    else:
                        mark = "  (n/a)"; gap = ""; all_beat = False
                    print(f"  {label_r:<22}: {v:>8.1f} km  {mark}{gap}")
                print(f"  {'ÔöÇ'*66}")
                if all_beat:
                    print("  ­čĆć­čĆć­čĆć  ALL TARGETS BEATEN  ÔÇö v62 beats ST-Trans!  ­čĆć­čĆć­čĆć")
                print(f"{'ÔĽÉ'*70}")

    print("=" * 80)


if __name__ == "__main__":
    args = get_args()
    np.random.seed(42); torch.manual_seed(42)
    if torch.cuda.is_available(): torch.cuda.manual_seed_all(42)
    main(args)